import{_ as o,o as p,c as a,a5 as s}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"教程 0033：UPS 命令响应与拒绝原因","description":"","frontmatter":{"title":"教程 0033：UPS 命令响应与拒绝原因","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0033-ups-command-response.html","status":"learning","visibility":"public","summary":"Imported from 0033-ups-command-response.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0033-ups-command-response.md","filePath":"content/power/lessons/0033-ups-command-response.md","lastUpdated":null}'),d={name:"content/power/lessons/0033-ups-command-response.md"};function l(n,e,r,c,i,t){return p(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="教程-0033-ups-命令响应与拒绝原因" tabindex="-1">教程 0033：UPS 命令响应与拒绝原因 <a class="header-anchor" href="#教程-0033-ups-命令响应与拒绝原因" aria-label="Permalink to &quot;教程 0033：UPS 命令响应与拒绝原因&quot;">​</a></h1><p>中文主讲。一个概念：命令被拒绝时也要返回可诊断原因，外部工具不应该靠猜。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学响应码，不包含公司内部通信响应码、协议错误码、客户项目参数或未公开产品方案。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>命令响应（command response）是固件处理外部命令后返回给外部工具的结果说明。响应码（response code）说明命令处理结果，例如 <code>OK</code>、<code>ACCEPTED</code>、<code>REJECTED</code>。拒绝原因（reject reason）说明为什么命令没有被执行，例如 <code>NOT_SAFE_TO_CLEAR</code>。</p><p>本课只讲一个概念：命令被拒绝时也要返回可诊断原因，而不是让外部工具猜。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>上一节讲了命令解析（command parsing）和安全门控（safety gating）。安全门控拒绝清故障请求（clear fault request）后，外部工具还需要知道“是通信坏了、命令错了，还是安全条件不满足”。没有响应码，调试人员会把安全拒绝误判成通信故障。</p><p>UPS 中很多命令会影响故障锁存、输出许可或模式切换。响应码能把“命令已看懂”和“动作是否执行”分开表达。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>命令响应像值班工程师给外部工具回话：读状态请求可以说“OK”；不安全的清故障请求要说“拒绝，原因是当前不安全”；安全条件满足后的清故障请求可以说“已接受”。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>parsed = parse(raw_command) gated = apply_safety_gate(parsed, safe_to_clear_fault)</p><p>if parsed.type == READ_STATUS: response_code = OK reject_reason = NONE</p><p>if parsed.type == CLEAR_FAULT_REQUEST and gated.request_clear_fault: response_code = ACCEPTED reject_reason = NONE</p><p>if parsed.type == CLEAR_FAULT_REQUEST and not gated.request_clear_fault: response_code = REJECTED reject_reason = NOT_SAFE_TO_CLEAR</p><p>本课只建三个教学响应码，不实现真实协议的异常码表。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_command_response.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_command_response.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_command_response.png</code></p></li><li><p>终端输出：被拒绝命令数量、被接受清故障数量、OK 状态数量。</p></li><li><p>图内包含参数框、图例、命令类型、响应码和拒绝原因。</p></li></ul><p>观察顺序：先看 0 ms 的读状态命令返回 <code>OK</code>；再看 20 ms 的不安全清故障返回 <code>REJECTED / NOT_SAFE_TO_CLEAR</code>；最后看 40 ms 的安全清故障返回 <code>ACCEPTED</code>。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsCommandResponseCode</code>：教学响应码枚举。</p></li><li><p><code>UPS_RESPONSE_OK</code>：读状态这类不改变安全状态的命令处理成功。</p></li><li><p><code>UPS_RESPONSE_ACCEPTED</code>：需要执行的命令已被接受。</p></li><li><p><code>UPS_RESPONSE_REJECTED</code>：命令被拒绝。</p></li><li><p><code>UpsRejectReason</code>：教学拒绝原因枚举。</p></li><li><p><code>UPS_REJECT_REASON_NOT_SAFE_TO_CLEAR</code>：当前不满足清故障安全条件。</p></li><li><p><code>UpsCommandResponse_FromCommand()</code>：根据原始命令、安全门控后的命令和安全条件生成响应。</p></li><li><p><code>UpsCommandResponse_Print()</code>：打印可检查证据。</p></li></ul><p>真实工程可能还会包含协议校验失败、权限不足、参数越界、忙碌、超时和版本不匹配等响应。本课只训练最小阅读路径。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**命令被拒绝就不用回复。 **纠正：**拒绝也应该尽量说明原因，否则外部工具无法区分安全拒绝和通信故障。</p></li><li><p>**误解：**响应码等于故障码。 **纠正：**故障码描述设备故障；响应码描述通信命令处理结果。</p></li><li><p>**误解：**可以把导师给的真实响应码表记到学习仓库。 **纠正：**不能记录公司内部通信响应码，只能记录通用分类方法。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_command_response.py --no-open</code> 并打开 <code>simulations/results/ups_command_response.png</code>。</p></li><li><p>能解释响应码和拒绝原因的区别。</p></li><li><p>能解释为什么 <code>REJECTED</code> 不是通信失败，而是一个明确处理结果。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>command_response</code> 输出。</p></li><li><p>能基于 <code>command_response.c -&gt; UpsCommandResponse_FromCommand()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么命令响应码不应该和故障码混在一起？</p></li><li><p>为什么安全拒绝需要明确原因？</p></li><li><p>如果外部工具收到 <code>REJECTED / NOT_SAFE_TO_CLEAR</code>，下一步应该读取状态、等待条件满足，还是重复发送命令？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>command_response.c -&gt; UpsCommandResponse_FromCommand()</code> 区分 <code>OK</code>、<code>ACCEPTED</code> 和 <code>REJECTED</code>。真实工程里通常如何区分“已收到”“已执行”和“拒绝执行”？</p></li><li><p>我用 <code>simulations/results/ups_command_response.png</code> 看到不安全清故障返回 <code>NOT_SAFE_TO_CLEAR</code>。真实工程中拒绝原因通常会细分到什么程度？</p></li><li><p>我不会记录公司内部通信响应码，只想确认阅读方式：看真实工程时，响应码表、命令解析表和故障码表应该分开看还是合在一起看？</p></li></ul><p>**下一步：**可以继续补“参数读写边界”，训练哪些参数只能读、哪些参数可写、写入前如何限幅和校验。</p><p>关联：<a href="./0032-ups-command-parser.html">上一节：命令解析与安全门控</a>；源稿：<code>concepts/embedded/ups-command-response.md</code>；仿真：<code>simulations/python/ups_command_response.py</code>。</p><pre><code>上一节：教程 0032：UPS 命令解析与安全门控
下一节：教程 0034：UPS 参数访问边界
</code></pre>`,41)])])}const u=o(d,[["render",l]]);export{m as __pageData,u as default};
